//  AUTO-MERGE into ALL_CHAPTERS
//  Runs after data.js loads ALL_CHAPTERS
// ─────────────────────────────────────────────
(function mergeBatch2() {
  if (typeof ALL_CHAPTERS === 'undefined') {
    console.error('Footy Brain: data.js must load before data-batch2.js');
    return;
  }
  const existingIds = new Set(ALL_CHAPTERS.map(c => c.id));
  BATCH2_CHAPTERS.forEach(ch => {
    if (!existingIds.has(ch.id)) {
      ALL_CHAPTERS.push(ch);
    }
  });
  // Re-sort by order
  ALL_CHAPTERS.sort((a, b) => (a.order || 99) - (b.order || 99));
  console.log(`Footy Brain: Batch 2 loaded — ${ALL_CHAPTERS.length} total chapters, ${ALL_CHAPTERS.reduce((t,c)=>t+c.questions.length,0)} total questions`);
})();
